import React, { useState, useEffect } from 'react';
import authService from '../services/auth';
import messageService from '../services/message';
import '../styles/Contact.css';

const Contact = () => {
    const [formData, setFormData] = useState({
        content: ''
    });
    
    const [authData, setAuthData] = useState({
        username: '',
        email: '',
        password: '',
        confirmPassword: '',
        isAdmin: false
    });
    
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [submitStatus, setSubmitStatus] = useState(null);
    const [error, setError] = useState(null);
    const [user, setUser] = useState(null);
    const [showSignUp, setShowSignUp] = useState(false);
    const [messages, setMessages] = useState([]);

    useEffect(() => {
        const currentUser = authService.getCurrentUser();
        if (currentUser) {
            setUser(currentUser);
            loadMessages();
        }
    }, []);

    const loadMessages = async () => {
        try {
            const data = await messageService.getUserMessages();
            setMessages(data);
        } catch (err) {
            setError(err.message || 'Failed to load messages');
        }
    };

    const handleChange = (e) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleAuthChange = (e) => {
        const { name, value, type, checked } = e.target;
        setAuthData(prev => ({
            ...prev,
            [name]: type === 'checkbox' ? checked : value
        }));
    };

    const validateForm = () => {
        if (!formData.content.trim()) {
            setError('Message content is required');
            return false;
        }
        if (formData.content.length > 5000) {
            setError('Message is too long (max 5000 characters)');
            return false;
        }
        setError(null);
        return true;
    };

    const validateAuthForm = (isLogin) => {
        if (isLogin) {
            if (!authData.email || !authData.password) {
                setError('Email and password are required');
                return false;
            }
        } else {
            if (!authData.username || !authData.email || !authData.password || !authData.confirmPassword) {
                setError('All fields are required');
                return false;
            }
            if (authData.password !== authData.confirmPassword) {
                setError('Passwords do not match');
                return false;
            }
            if (authData.password.length < 6) {
                setError('Password must be at least 6 characters');
                return false;
            }
        }
        setError(null);
        return true;
    };

    const handleLogin = async (e) => {
        e.preventDefault();
        if (!validateAuthForm(true)) return;

        setIsSubmitting(true);
        try {
            const data = await authService.login({
                email: authData.email,
                password: authData.password
            });
            
            setUser(data.user);
            setSubmitStatus('success');
            setError(null);
            setAuthData({
                username: '',
                email: '',
                password: '',
                confirmPassword: '',
                isAdmin: false
            });
            await loadMessages();
        } catch (err) {
            setError(err.message || 'Login failed');
            setSubmitStatus('error');
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleSignup = async (e) => {
        e.preventDefault();
        if (!validateAuthForm(false)) return;

        setIsSubmitting(true);
        try {
            await authService.register({
                username: authData.username,
                email: authData.email,
                password: authData.password,
                isAdmin: authData.isAdmin
            });
            
            setSubmitStatus('success');
            setError(null);
            setShowSignUp(false);
            setAuthData({
                username: '',
                email: '',
                password: '',
                confirmPassword: '',
                isAdmin: false
            });
        } catch (err) {
            setError(err.message || 'Registration failed');
            setSubmitStatus('error');
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!validateForm()) return;

        setIsSubmitting(true);
        try {
            await messageService.sendMessage(formData.content);
            
            setSubmitStatus('success');
            setError(null);
            setFormData({ content: '' });
            await loadMessages();
        } catch (err) {
            setError(err.message || 'Failed to send message');
            setSubmitStatus('error');
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleLogout = () => {
        authService.logout();
        setUser(null);
        setMessages([]);
        setSubmitStatus(null);
    };

  return (
    <div id="contact" className="contact-container">
      <h1>CONTACT US</h1>

      <div className="map-container">
        <iframe
          title="Google Map"
          className="google-map"
          src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3048.146201882546!2d44.62674911141569!3d40.18355967135914!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x406aa5fb2d2aeb97%3A0x7a90e13129b8e750!2z1Y7VuNaC1aTVvSDUv9Wl1bbVv9aA1bjVtg!5e0!3m2!1shy!2sam!4v1743157411782!5m2!1shy!2sam"
          allowFullScreen
          loading="lazy"
          referrerPolicy="no-referrer-when-downgrade"
        ></iframe>
      </div>

      <div className="contact-content">
        <div className="contact-info">
          <h2>Law Office</h2>
          <div className="info-item">
            <span className="icon">📍</span>
            <div>
              <h3>Address</h3>
              <p>Armenia, Yerevan City</p>
              <p>Woods Centre</p>
            </div>
          </div>
          <div className="info-item">
            <span className="icon">📞</span>
            <div>
              <h3>Phone</h3>
              <p>+374 12 34 56 78</p>
            </div>
          </div>
          <div className="info-item">
            <span className="icon">📧</span>
            <div>
              <h3>E-mail</h3>
              <p>info@law.com</p>
            </div>
          </div>
        </div>

        <div className="contact-form">
          {isLoggedIn ? (
            <>
              <div className="user-header">
                <h3>Welcome, {userInfo?.userName || "User"}!</h3>
                {showSignUp && (
  <div className="form-group">
    <label>
      <input
        type="checkbox"
        name="isAdmin"
        checked={authData.isAdmin || false}
        onChange={(e) => setAuthData({...authData, isAdmin: e.target.checked})}
      />
      Register as Admin
    </label>
  </div>
)}
                <button onClick={handleLogout} className="logout-btn">Logout</button>
              </div>
              
              <h4>LEAVE US A MESSAGE</h4>
              
              {error && (
                <div className="error-message">
                  ❌ {error}
                </div>
              )}

              {submitStatus === "success" && (
                <div className="success-message">
                  ✅ {formData.fullName ? "Thank you! Your message has been sent." : "Authentication successful"}
                </div>
              )}

              <form onSubmit={handleSubmit}>
                <input
                  type="text"
                  name="fullName"
                  placeholder="Your Full Name"
                  value={formData.fullName}
                  onChange={handleChange}
                  required
                />
                <input
                  type="email"
                  name="email"
                  placeholder="example@email.com"
                  value={formData.email}
                  onChange={handleChange}
                  required
                />
                <input
                  type="tel"
                  name="phoneNumber"
                  placeholder="Phone Number (optional)"
                  value={formData.phoneNumber}
                  onChange={handleChange}
                />
                <input
                  type="text"
                  name="subject"
                  placeholder="Subject"
                  value={formData.subject}
                  onChange={handleChange}
                  required
                />
                <textarea
                  name="message"
                  placeholder="Write your message here..."
                  value={formData.message}
                  onChange={handleChange}
                  required
                ></textarea>

                <button 
                  type="submit" 
                  disabled={isSubmitting}
                  className={isSubmitting ? "submitting" : ""}
                >
                  {isSubmitting ? (
                    <>
                      <span className="spinner"></span>
                      Sending...
                    </>
                  ) : (
                    "Submit Message"
                  )}
                </button>
              </form>
            </>
          ) : showSignUp ? (
            <>
              <h3>SIGN UP</h3>
              
              {error && (
                <div className="error-message">
                  ❌ {error}
                </div>
              )}

              {submitStatus === "success" && (
                <div className="success-message">
                  ✅ Registration successful! Please sign in.
                </div>
              )}

              <form onSubmit={handleSignup}>
                <input
                  type="text"
                  name="username"
                  placeholder="Username"
                  value={authData.username}
                  onChange={handleAuthChange}
                  required
                />
                <input
                  type="email"
                  name="email"
                  placeholder="Email"
                  value={authData.email}
                  onChange={handleAuthChange}
                  required
                />
                <input
                  type="password"
                  name="password"
                  placeholder="Password (min 6 characters)"
                  value={authData.password}
                  onChange={handleAuthChange}
                  required
                />
                <input
                  type="password"
                  name="confirmPassword"
                  placeholder="Confirm Password"
                  value={authData.confirmPassword}
                  onChange={handleAuthChange}
                  required
                />

                <button 
                  type="submit" 
                  disabled={isSubmitting}
                  className={isSubmitting ? "submitting" : ""}
                >
                  {isSubmitting ? (
                    <>
                      <span className="spinner"></span>
                      Signing Up...
                    </>
                  ) : (
                    "Sign Up"
                  )}
                </button>
              </form>
              
              <p className="auth-switch">
                Already have an account? 
                <button onClick={() => setShowSignUp(false)}>Sign In</button>
              </p>
            </>
          ) : (
            <>
              <h3>SIGN IN</h3>
              
              {error && (
                <div className="error-message">
                  ❌ {error}
                </div>
              )}

              {submitStatus === "success" && (
                <div className="success-message">
                  ✅ Login successful!
                </div>
              )}

              <form onSubmit={handleLogin}>
                <input
                  type="email"
                  name="email"
                  placeholder="Email"
                  value={authData.email}
                  onChange={handleAuthChange}
                  required
                />
                <input
                  type="password"
                  name="password"
                  placeholder="Password"
                  value={authData.password}
                  onChange={handleAuthChange}
                  required
                />

                <button 
                  type="submit" 
                  disabled={isSubmitting}
                  className={isSubmitting ? "submitting" : ""}
                >
                  {isSubmitting ? (
                    <>
                      <span className="spinner"></span>
                      Signing In...
                    </>
                  ) : (
                    "Sign In"
                  )}
                </button>
              </form>
              
              <p className="auth-switch">
                Don't have an account? 
                <button onClick={() => setShowSignUp(true)}>Sign Up</button>
              </p>
            </>
          )}
        </div>
      </div>
    </div>
  );
};

export default Contact;
